customCSS:
/* Phi Forge — The Golden Ratio */
@import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@400;500;600;700&family=Inter:wght@300;400;500;600&family=Fira+Code&display=swap');

.cyber-glow {
  background:
    radial-gradient(ellipse 610px 377px at 38.2% 0%, rgba(212, 160, 32, 0.1), transparent),
    radial-gradient(ellipse 377px 233px at 61.8% 100%, rgba(136, 104, 192, 0.06), transparent);
}

.cyber-particles { opacity: 0.25; }

.stat-card {
  border: 1px solid rgba(212, 160, 32, 0.12);
  backdrop-filter: blur(10px);
  background: rgba(26, 24, 34, 0.85);
}

.stat-card::before {
  background: linear-gradient(137.5deg, #d4a020, #f0d060, #8868c0);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(212, 160, 32, 0.3);
  box-shadow: 0 4px 24px rgba(212, 160, 32, 0.12);
}

.stat-value {
  text-shadow: 0 0 16px rgba(212, 160, 32, 0.4);
}

.celebration-title {
  background: linear-gradient(137.5deg, #d4a020, #ffd700, #8868c0);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
  filter: drop-shadow(0 0 18px rgba(212, 160, 32, 0.35));
}

.miner-card, .health-card, .lifetime-card {
  border: 1px solid rgba(212, 160, 32, 0.08);
  background: rgba(26, 24, 34, 0.7);
}

.miner-card:hover {
  border-color: rgba(136, 104, 192, 0.2);
}

.logo {
  color: #d4a020;
  text-shadow: 0 0 18px rgba(212, 160, 32, 0.35);
}
